/**
 * Error type returned by every public binding function.
 *
 * The variants distinguish the broad failure category so callers can branch
 * on them in Kotlin/Swift; the inner message preserves the full anyhow chain
 * for human-readable diagnostics.
 */
public enum DcapError {
    /**
     * The quote, collateral, or PEM input could not be parsed.
     */
    case Parse(message: String)

    /**
     * Verification failed (signature, certificate chain, TCB, or QE identity).
     */
    case Verify(message: String)
}

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
public struct FfiConverterTypeDcapError: FfiConverterRustBuffer {
    typealias SwiftType = DcapError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> DcapError {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        case 1: return try .Parse(
                message: FfiConverterString.read(from: &buf)
            )

        case 2: return try .Verify(
                message: FfiConverterString.read(from: &buf)
            )

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: DcapError, into buf: inout [UInt8]) {
        switch value {
        case .Parse(_ /* message is ignored*/ ):
            writeInt(&buf, Int32(1))
        case .Verify(_ /* message is ignored*/ ):
            writeInt(&buf, Int32(2))
        }
    }
}

extension DcapError: Equatable, Hashable {}

extension DcapError: Foundation.LocalizedError {
    public var errorDescription: String? {
        String(reflecting: self)
    }
}

