/* 
 * Tagged-union report: one of SGX, TDX 1.0, or TDX 1.5.
 */

public enum Report {
    case sgx(report: SgxReport)
    case td10(report: Td10Report)
    case td15(report: Td15Report)
}

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
public struct FfiConverterTypeReport: FfiConverterRustBuffer {
    typealias SwiftType = Report

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Report {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        case 1: return try .sgx(report: FfiConverterTypeSgxReport.read(from: &buf))

        case 2: return try .td10(report: FfiConverterTypeTd10Report.read(from: &buf))

        case 3: return try .td15(report: FfiConverterTypeTd15Report.read(from: &buf))

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: Report, into buf: inout [UInt8]) {
        switch value {
        case let .sgx(report):
            writeInt(&buf, Int32(1))
            FfiConverterTypeSgxReport.write(report, into: &buf)

        case let .td10(report):
            writeInt(&buf, Int32(2))
            FfiConverterTypeTd10Report.write(report, into: &buf)

        case let .td15(report):
            writeInt(&buf, Int32(3))
            FfiConverterTypeTd15Report.write(report, into: &buf)
        }
    }
}

